scode.Disposable {\n  private editor: vscode.TextEditor | undefined;\n\n  private decorationType: vscode.TextEditorDecorationType;\n\n  private interval: NodeJS.Timeout | undefined;\n\n  private delayed: NodeJS.Timeout | undefined;\n\n  private dotCount: number;\n\n  private dotPatterns: string[];\n\n  private range: vscode.Range;\n\n  private readonly INTERVAL = 80;\n\n  private readonly INITIAL_DELAY = 80;\n\n  private isEmptyLine: boolean | undefined;\n\n  private isEnabled: boolean;\n\n  constructor(position: vscode.Position) {\n    const theme = vscode.window.activeColorTheme;\n    const color =\n      theme.kind === vscode.ColorThemeKind.Light ? \"darkgray\" : \"lightgray\";\n    this.editor = vscode.window.activeTextEditor;\n    this.decorationType = vscode.window.createTextEditorDecorationType({\n      after: {\n        margin: \"0 0 0 0\",\n        color,\n        fontWeight: \"900\",\n      },\n    });\n    this.dotCount = 0;\n    this.dotPatterns = [\"⣷\", \"⣯\", \"⣟\", \"⡿\", \"⢿\", \"⣻\", \"⣽\", \"⣾\"];\n\n    this.range = new vscode.Range(position, position);\n    this.isEmptyLine = this.editor?.document.lineAt(\n      position\n    ).isEmptyOrWhitespace;\n    const isSpinnerDisabled = isCapabilityEnabled(\n      Capability.INLINE_COMPLETIONS_SPINNER_DISABLED\n    );\n    if (isSpinnerDisabled) {\n      this.isEnabled = false;\n    } else {\n      this.isEnabled =\n        tabnineExtensionProperties.completionsLoadingIndicatorEnabled ?? true;\n    }\n  }\n\n  dispose() {\n    if (this.editor) {\n      this.editor.setDecorations(this.decorationType, []);\n    }\n    if (this.delayed) {\n      clearTimeout(this.delayed);\n      this.delayed = undefined;\n    }\n    if (this.interval) {\n      clearInterval(this.interval);\n      this.interval = undefined;\n    }\n    if (!this.isEnabled) {\n      return;\n    }\n    this.editor = undefined;\n  }\n\n  start(): void {\n    if (this.editor && this.isEmptyLine && this.isEnabled) {\n      this.delayed = setTimeout(() => {\n        this.interval = setInterval(\n          () => this.updateDecoration(),\n          this.INTERVAL\n        );\n      }, this.INITIAL_DELAY);\n    }\n  }\n\n  private updateDecoration(): void {\n    this.dotCount = (this.dotCount + 1) % this.dotPatterns.length;\n    const dots = this.dotPatterns[this.dotCount];\n    const decorationOptions: vscode.DecorationOptions[] = [\n      {\n        range: this.range,\n        renderOptions: {\n          after: {\n            contentText: dots,\n          },\n        },\n      },\n    ];\n    this.editor?.setDecorations(this.decorationType, decorationOptions);\n  }\n}\n","import * as vscode from \"vscode\";\nimport { BINARY_UPDATE_WORKSPACE_INTERVAL } from \"./globals/consts\";\nimport sendUpdateWorkspaceRequest from \"./binary/requests/workspace\";\nimport { Logger } from \"./utils/logger\";\nimport { tabNineProcess } from \"./binary/requests/requests\";\nimport { getWorkspaceRootPaths } from \"./utils/workspaceFolders\";\n\nconst INITIAL_DELAY = 3000;\n\nexport class WorkspaceUpdater implements vscode.Disposable {\n  private updateInterval: NodeJS.Timeout | null = null;\n\n  constructor() {\n    void tabNineProcess.onReady.then(() => {\n      setTimeout(() => {\n        updateWorkspace();\n        this.updateInterval = setInterval(\n          updateWorkspace,\n          BINARY_UPDATE_WORKSPACE_INTERVAL\n        );\n      }, INITIAL_DELAY);\n    });\n  }\n\n  dispose() {\n    if (this.updateInterval) {\n      clearInterval(this.updateInterval);\n    }\n  }\n}\n\nfunction updateWorkspace() {\n  const rootPaths = getWorkspaceRootPaths() || [];\n\n  Logger.debug(\n    `Updating root paths for project ${\n      vscode.workspace.name || \"unknown\"\n    }: ${JSON.stringify(rootPaths)}`\n  );\n\n  void sendUpdateWorkspaceRequest({\n    root_paths: rootPaths,\n  });\n}\n","import * as vscode from \"vscode\";\nimport { prefetch } from \"./binary/requests/prefetch\";\nimport { sendEvent } from \"./binary/requests/sendEvent\";\n\n// Notify the binary on changes to the active text editor.\nexport const activeTextEditorState = vscode.window.onDidChangeActiveTextEditor(\n  async (editor) => {\n    if (editor) {\n      void sendEvent({\n        name: \"active_text_editor_changed\",\n        properties: {\n          isDirty: editor.document.isDirty.toString(),\n        },\n      });\n      const filename = editor.document.uri.fsPath;\n      await prefetch({ filename });\n    }\n  }\n);\n","import * as vscode from \"vscode\";\nimport setState from \"../binary/requests/setState\";\nimport { Capability, isCapabilityEnabled } from \"../capabilities/capabilities\";\nimport { StatePayload } from \"../globals/consts\";\nimport registerAssistant from \"./diagnostics\";\nimport { downloadAssistantBinary, StateType } from \"./utils\";\nimport {\n  assistantClearCacheHandler,\n  assistantIgnoreHandler,\n  assistantSelectionHandler,\n} from \"./AssistantHandlers\";\nimport { setAssistantMode, AssistantMode } from \"./AssistantMode\";\nimport {\n  ACTIVE_STATE_KEY,\n  ASSISTANT_CLEAR_CACHE_COMMAND,\n  ASSISTANT_IGNORE_COMMAND,\n  ASSISTANT_SELECTION_COMMAND,\n  ASSISTANT_TOGGLE_COMMAND,\n  BACKGROUND_KEY,\n  CAPABILITY_KEY,\n  ENABLED_KEY,\n} from \"./globals\";\nimport { IgnoreAssistantSelection } from \"./IgnoreAssistantSelection\";\nimport { AcceptAssistantSelection } from \"./AcceptAssistantSelection\";\nimport { reloadOrRestart } from \"../globals/extensionHostReloader\";\n\nexport default async function initAssistant(\n  context: vscode.ExtensionContext,\n  pasteDisposable: vscode.Disposable\n): Promise<void> {\n  await vscode.commands.executeCommand(\"setContext\", CAPABILITY_KEY, true);\n\n  setAssistantMode(AssistantMode.Background);\n  let backgroundMode = true;\n\n  if (isCapabilityEnabled(Capability.ASSISTANT_BACKGROUND_CAPABILITY)) {\n    // use default values\n  } else if (isCapabilityEnabled(Capability.ASSISTANT_PASTE_CAPABILITY)) {\n    backgroundMode = false;\n    setAssistantMode(AssistantMode.Paste);\n  }\n  await vscode.commands.executeCommand(\n    \"setContext\",\n    BACKGROUND_KEY,\n    backgroundMode\n  );\n\n  let isActive = context.globalState.get(ACTIVE_STATE_KEY, backgroundMode);\n  if (isActive === null || typeof isActive === \"undefined\") {\n    isActive = true;\n  }\n  registerReloadForToggleCommand(context, isActive);\n\n  if (isActive) {\n    const isDownloaded = await downloadAssistantBinary();\n    if (isDownloaded) {\n      pasteDisposable.dispose();\n      await registerAssistant(context, pasteDisposable);\n\n      context.subscriptions.push(\n        vscode.commands.registerTextEditorCommand(\n          ASSISTANT_SELECTION_COMMAND,\n          (\n            editor: vscode.TextEditor,\n            edit: vscode.TextEditorEdit,\n            data: AcceptAssistantSelection\n          ) => void assistantSelectionHandler(editor, edit, data)\n        )\n      );\n      context.subscriptions.push(\n        vscode.commands.registerTextEditorCommand(\n          ASSISTANT_IGNORE_COMMAND,\n          (\n            editor: vscode.TextEditor,\n            edit: vscode.TextEditorEdit,\n            data: IgnoreAssistantSelection\n          ) => void assistantIgnoreHandler(editor, edit, data)\n        )\n      );\n      if (backgroundMode) {\n        context.subscriptions.push(\n          vscode.commands.registerCommand(\n            ASSISTANT_CLEAR_CACHE_COMMAND,\n            assistantClearCacheHandler\n          )\n        );\n      }\n      await vscode.commands.executeCommand(\"setContext\", ENABLED_KEY, true);\n    }\n  }\n}\n\nfunction registerReloadForToggleCommand(\n  context: vscode.ExtensionContext,\n  isActive: boolean\n) {\n  context.subscriptions.push(\n    vscode.commands.registerCommand(ASSISTANT_TOGGLE_COMMAND, async () => {\n      const value = !isActive ? \"On\" : \"Off\";\n      const message = `Please reload Visual Studio Code to turn Assistant ${value}.`;\n      const reload = await vscode.window.showInformationMessage(\n        message,\n        \"Reload Now\"\n      );\n      if (reload) {\n        void setState({\n          [StatePayload.STATE]: { state_type: StateType.toggle, state: value },\n        });\n        await context.globalState.update(ACTIVE_STATE_KEY, !isActive);\n        void reloadOrRestart();\n      }\n    })\n  );\n}\n","import * as vscode from \"vscode\";\nimport { Completion } from \"./Completion\";\nimport { getAssistantMode, AssistantMode } from \"./AssistantMode\";\n\nimport {\n  ASSISTANT_IGNORE_COMMAND,\n  ASSISTANT_SELECTION_COMMAND,\n  TABNINE_DIAGNOSTIC_CODE,\n} from \"./globals\";\nimport TabNineDiagnostic from \"./TabNineDiagnostic\";\n\nexport default class AssistantCodeActionProvider\n  implements vscode.CodeActionProvider {\n  public static readonly providedCodeActionKinds = [\n    vscode.CodeActionKind.QuickFix,\n  ];\n\n  // This method implements vscode.CodeActionProvider\n  // eslint-disable-next-line class-methods-use-this\n  provideCodeActions(\n    document: vscode.TextDocument,\n    range: vscode.Range | vscode.Selection,\n    context: vscode.CodeActionContext\n  ): vscode.CodeAction[] {\n    const codeActions: vscode.CodeAction[] = [];\n    const diagnostics = context.diagnostics as TabNineDiagnostic[];\n    diagnostics\n      .filter((diagnostic) => diagnostic.code === TABNINE_DIAGNOSTIC_CODE)\n      .forEach((diagnostic) => {\n        diagnostic.choices.forEach((choice) => {\n          codeActions.push(createCodeAction(document, diagnostic, choice));\n        });\n        // register ignore action\n        const title = \"Ignore TabNine Assistant suggestions at this spot\";\n        const action = new vscode.CodeAction(\n          title,\n          vscode.CodeActionKind.QuickFix\n        );\n        action.command = {\n          arguments: [\n            {\n              allSuggestions: diagnostic.choices,\n              reference: diagnostic.reference,\n              threshold: diagnostic.threshold,\n              responseId: diagnostic.responseId,\n            },\n          ],\n          command: ASSISTANT_IGNORE_COMMAND,\n          title: \"ignore replacement\",\n        };\n        codeActions.push(action);\n      });\n    return codeActions;\n  }\n}\n\nfunction createCodeAction(\n  document: vscode.TextDocument,\n  diagnostic: TabNineDiagnostic,\n  choice: Completion\n): vscode.CodeAction {\n  const { range } = diagnostic;\n  const title = `${choice.message} '${choice.value}'`;\n  const action = new vscode.CodeAction(title, vscode.CodeActionKind.QuickFix);\n  action.edit = new vscode.WorkspaceEdit();\n  action.edit.replace(\n    document.uri,\n    new vscode.Range(range.start, range.end),\n    choice.value\n  );\n  if (getAssistantMode() === AssistantMode.Paste) {\n    diagnostic.references.forEach((r) =>\n      action.edit?.replace(document.uri, r, choice.value)\n    );\n  }\n  action.diagnostics = [diagnostic];\n  action.command = {\n    arguments: [\n      {\n        currentSuggestion: choice,\n        allSuggestions: diagnostic.choices,\n        reference: diagnostic.reference,\n        threshold: diagnostic.threshold,\n      },\n    ],\n    command: ASSISTANT_SELECTION_COMMAND,\n    title: \"accept replacement\",\n  };\n  return action;\n}\n","import * as vscode from \"vscode\";\nimport setState, {\n  AssistantSelectionStateRequest,\n} from \"../binary/requests/setState\";\nimport CompletionOrigin from \"../CompletionOrigin\";\nimport { StatePayload } from \"../globals/consts\";\nimport { StateType } from \"./utils\";\nimport clearCache from \"./requests/clearCache\";\nimport { Completion } from \"./Completion\";\nimport setIgnore from \"./requests/setIgnore\";\nimport { getAssistantVersion } from \"./requests/request\";\nimport { ASSISTANT_IGNORE_REFRESH_COMMAND } from \"./globals\";\nimport { IgnoreAssistantSelection } from \"./IgnoreAssistantSelection\";\nimport { AcceptAssistantSelection } from \"./AcceptAssistantSelection\";\nimport { setDecorators } from \"./diagnostics\";\nimport { Logger } from \"../utils/logger\";\n\nconst IGNORE_VALUE = \"__IGNORE__\";\n\nexport async function assistantClearCacheHandler(): Promise<void> {\n  await clearCache();\n  void setState({\n    [StatePayload.STATE]: { state_type: StateType.clearCache },\n  });\n}\n\nexport async function assistantSelectionHandler(\n  editor: vscode.TextEditor,\n  edit: vscode.TextEditorEdit,\n  {\n    currentSuggestion,\n    allSuggestions,\n    reference,\n    threshold,\n  }: AcceptAssistantSelection\n): Promise<void> {\n  try {\n    setDecorators([]);\n    await vscode.commands.executeCommand(ASSISTANT_IGNORE_REFRESH_COMMAND);\n    const assistantVersion = await getAssistantVersion();\n    const eventData = eventDataOf(\n      editor,\n      currentSuggestion,\n      allSuggestions,\n      reference,\n      threshold,\n      false,\n      assistantVersion\n    );\n    void setState(eventData);\n  } catch (error) {\n    Logger.error(error);\n  }\n}\n\nexport async function assistantIgnoreHandler(\n  editor: vscode.TextEditor,\n  edit: vscode.TextEditorEdit,\n  { allSuggestions, reference, threshold, responseId }: IgnoreAssistantSelection\n): Promise<void> {\n  try {\n    await setIgnore(responseId);\n    setDecorators([]);\n    const assistantVersion = await getAssistantVersion();\n\n    void vscode.commands.executeCommand(ASSISTANT_IGNORE_REFRESH_COMMAND);\n    const completion: Completion = {\n      value: IGNORE_VALUE,\n      score: 0,\n      message: \"\",\n    };\n    const eventData = eventDataOf(\n      editor,\n      completion,\n      allSuggestions,\n      reference,\n      threshold,\n      true,\n      assistantVersion\n    );\n    void setState(eventData);\n  } catch (error) {\n    Logger.error(error);\n  }\n}\n\nfunction eventDataOf(\n  editor: vscode.TextEditor,\n  currentSuggestion: Completion,\n  allSuggestions: Completion[],\n  reference: string,\n  threshold: string,\n  isIgnore = false,\n  assistantVersion: string\n): AssistantSelectionStateRequest {\n  let index = allSuggestions.findIndex((sug) => sug === currentSuggestion);\n  if (index === -1) {\n    index = allSuggestions.length;\n  }\n  const suggestions = allSuggestions.map((sug) => ({\n    length: sug.value.length,\n    strength: resolveDetailOf(sug),\n    origin: CompletionOrigin.CLOUD,\n  }));\n\n  const { length } = currentSuggestion.value;\n  const selectedSuggestion = currentSuggestion.value;\n  const strength = resolveDetailOf(currentSuggestion);\n  const origin = CompletionOrigin.CLOUD;\n  const language = editor.document.fileName.split(\".\").pop() || \"\";\n  const numOfSuggestions = allSuggestions.length;\n\n  const eventData: AssistantSelectionStateRequest = {\n    AssistantSelection: {\n      language,\n      length,\n      strength,\n      origin,\n      index,\n      threshold,\n      num_of_suggestions: numOfSuggestions,\n      suggestions,\n      selected_suggestion: selectedSuggestion,\n      reference,\n      reference_length: reference.length,\n      is_ignore: isIgnore,\n      assistant_version: assistantVersion,\n    },\n  };\n\n  return eventData;\n}\n\nfunction resolveDetailOf(completion: Completion): string {\n  return `${completion.score}%`;\n}\n","export enum AssistantMode {\n  Background,\n  Paste,\n}\n\nlet assistantMode: AssistantMode = AssistantMode.Background;\n\nexport function setAssistantMode(m: AssistantMode): void {\n  assistantMode = m;\n}\n\nexport function getAssistantMode(): AssistantMode {\n  return assistantMode;\n}\n","import { Mutex } from \"await-semaphore\";\nimport * as child_process from \"child_process\";\nimport * as readline from \"readline\";\nimport run from \"./runAssistant\";\nimport { Logger } from \"../utils/logger\";\n\nexport default class AssistantProcess {\n  private proc?: child_process.ChildProcess;\n\n  private rl?: readline.ReadLine;\n\n  private numRestarts = 0;\n\n  private childDead = false;\n\n  private mutex: Mutex = new Mutex();\n\n  private resolveMap = new Map();\n\n  private isShutdown = false;\n\n  constructor() {\n    this.restartChild();\n  }\n\n  async post<T extends { id: number; version: string }, R>(\n    anyRequest: T,\n    id: number,\n    timeToSleep = 10000\n  ): Promise<R | undefined> {\n    const release = await this.mutex.acquire();\n\n    try {\n      if (!this.isChildAlive()) {\n        this.restartChild();\n      }\n      const request = `${JSON.stringify(anyRequest)}\\n`;\n      this.proc?.stdin?.write(request, \"utf8\");\n\n      return await new Promise((resolve, reject) => {\n        this.resolveMap.set(id, resolve);\n        setTimeout(() => {\n          this.resolveMap.delete(id);\n          reject(new Error(\"Timeout\"));\n        }, timeToSleep);\n      });\n    } catch (e) {\n      Logger.error(`interacting with tabnine assistant: ${e}`);\n      return undefined;\n    } finally {\n      release();\n    }\n  }\n\n  get shutdowned(): boolean {\n    return this.isShutdown;\n  }\n\n  set shutdowned(value: boolean) {\n    this.isShutdown = value;\n  }\n\n  private isChildAlive(): boolean {\n    return !!this.proc && !this.childDead;\n  }\n\n  private onChildDeath() {\n    this.childDead = true;\n\n    setTimeout(() => {\n      if (!this.isChildAlive()) {\n        this.restartChild();\n      }\n    }, 10000);\n  }\n\n  private restartChild<R>(): void {\n    if (this.numRestarts >= 10) {\n      return;\n    }\n    this.numRestarts += 1;\n    if (this.proc) {\n      this.proc.kill();\n    }\n    this.proc = run();\n    this.childDead = false;\n    this.proc.on(\"exit\", () => {\n      if (!this.shutdowned) {\n        this.onChildDeath();\n      }\n    });\n    this.proc.stdin?.on(\"error\", (error) => {\n      Logger.error(`assistant binary stdin error: ${error.message}`);\n      this.onChildDeath();\n    });\n    this.proc.stdout?.on(\"error\", (error) => {\n      Logger.error(`assistant binary stdout error: ${error.message}`);\n      this.onChildDeath();\n    });\n    this.proc.unref(); // AIUI, this lets Node exit without waiting for the child\n    this.rl = readline.createInterface({\n      input: this.proc.stdout,\n      output: this.proc.stdin,\n    } as readline.ReadLineOptions);\n    this.rl.on(\"line\", (line) => {\n      const result = JSON.parse(line) as { id: number; body: R };\n      const { id } = result;\n      const { body } = result;\n      const resolve = this.resolveMap.get(id) as (data: R) => void | undefined;\n      if (resolve) {\n        resolve(body);\n        this.resolveMap.delete(id);\n      }\n    });\n  }\n}\n","export default class CancellationToken {\n  private cancelled = false;\n\n  private callbacks: [(...args: unknown[]) => void, unknown[]][] = [];\n\n  isCancelled(): boolean {\n    return this.cancelled;\n  }\n\n  cancel(): void {\n    if (!this.isCancelled()) {\n      this.cancelled = true;\n      this.callbacks.forEach(([callback, args]) => callback(args));\n    }\n  }\n\n  reset(): void {\n    this.cancelled = false;\n    this.callbacks = [];\n  }\n\n  registerCallback(\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    callback: (...args: any[]) => void,\n    ...args: unknown[]\n  ): void {\n    if (this.isCancelled()) {\n      callback(...args);\n    } else {\n      this.callbacks.push([callback, args]);\n    }\n  }\n}\n","import * as vscode from \"vscode\";\nimport getValidExtensions from \"./requests/getValidExtensions\";\nimport getValidLanguages from \"./requests/getValidLanguages\";\n\nexport class DocumentValidator {\n  private validLanguages: string[];\n\n  private validExtensions: string[];\n\n  constructor(validLanguages: string[], validExtensions: string[]) {\n    this.validLanguages = validLanguages;\n\n    this.validExtensions = validExtensions;\n  }\n\n  public isValid(document: vscode.TextDocument): boolean {\n    const { fileName } = document;\n    const fileExt = `.${fileName?.split(\".\").pop() || \"\"}`;\n    return (\n      this.validExtensions?.includes(fileExt) &&\n      this.validLanguages?.includes(document.languageId)\n    );\n  }\n}\n\nexport default async function getValidator(): Promise<DocumentValidator> {\n  const validLanguages = await getValidLanguages();\n  const validExtensions = await getValidExtensions();\n\n  const documentValidator = new DocumentValidator(\n    validLanguages,\n    validExtensions\n  );\n  return documentValidator;\n}\n","import * as vscode from \"vscode\";\nimport { Range } from \"./Range\";\nimport { Completion } from \"./Completion\";\n\nexport default class TabNineDiagnostic extends vscode.Diagnostic {\n  choices: Completion[] = [];\n\n  reference: string;\n\n  references: vscode.Range[] = [];\n\n  assistantRange: Range;\n\n  responseId: string;\n\n  threshold: string;\n\n  constructor(\n    range: vscode.Range,\n    message: string,\n    choices: Completion[],\n    reference: string,\n    vscodeReferencesRange: vscode.Range[],\n    assistantRange: Range,\n    responseId: string,\n    threshold: string,\n    severity?: vscode.DiagnosticSeverity\n  ) {\n    super(range, message, severity);\n    this.choices = choices;\n    this.reference = reference;\n    this.references = vscodeReferencesRange;\n    this.assistantRange = assistantRange;\n    this.responseId = responseId;\n    this.threshold = threshold;\n  }\n}\n","import * as vscode from \"vscode\";\nimport { Mutex } from \"await-semaphore\";\nimport CancellationToken from \"./CancellationToken\";\nimport {\n  getAssistantMode,\n  setAssistantMode,\n  AssistantMode,\n} from \"./AssistantMode\";\n\nimport { AssistantDiagnostic } from \"./AssistantDiagnostic\";\nimport { debounce, getAPIKey } from \"./utils\";\n\nimport setState from \"../binary/requests/setState\";\nimport getValidator, { DocumentValidator } from \"./DocumentValidator\";\nimport getAssistantDiagnostics from \"./requests/getAssistantDiagnostics\";\nimport getCompilerDiagnostics from \"./requests/getCompilerDiagnostics\";\nimport AssistantCodeActionProvider from \"./AssistantCodeActionProvider\";\nimport getValidLanguages from \"./requests/getValidLanguages\";\nimport TabNineDiagnostic from \"./TabNineDiagnostic\";\nimport {\n  ASSISTANT_IGNORE_REFRESH_COMMAND,\n  ASSISTANT_MODE_TOGGLE_COMMAND,\n  EDIT_DISTANCE,\n  PASTE_COMMAND,\n  PASTE_THRESHOLD,\n  TABNINE_DIAGNOSTIC_CODE,\n} from \"./globals\";\nimport {\n  initAssistantThreshold,\n  getBackgroundThreshold,\n} from \"./handleAssistantThreshold\";\nimport { Logger } from \"../utils/logger\";\n\nconst decorationType = vscode.window.createTextEditorDecorationType({\n  border: \"#3794FF 2px\",\n  borderStyle: \"none none solid none\",\n});\n\nconst changesTrackMap = new Map<vscode.Uri, vscode.Position>();\n\nexport function setDecorators(\n  diagnostics: vscode.Diagnostic[] | undefined\n): void {\n  const editor = vscode.window.activeTextEditor;\n  const decorationsArray: vscode.DecorationOptions[] =\n    diagnostics?.map(({ range }) => ({ range })) || [];\n  if (editor) {\n    editor.setDecorations(decorationType, decorationsArray);\n  }\n}\n\nfunction setStatusBarMessage(message?: string, timeout = 30000): void {\n  if (!message?.length) {\n    return;\n  }\n  vscode.window.setStatusBarMessage(`${message}`, timeout);\n}\n\nconst mutex: Mutex = new Mutex();\nconst cancellationToken = new CancellationToken();\n\nfunction getRelevantRange(\n  document: vscode.TextDocument,\n  visibleRanges: vscode.Range[]\n): vscode.Range | undefined {\n  const firstEditingPosition = changesTrackMap.get(document.uri);\n  const visibleRange = visibleRanges.reduce((accumulator, currentValue) =>\n    accumulator.union(currentValue)\n  );\n\n  return (\n    firstEditingPosition &&\n    visibleRange.intersection(\n      new vscode.Range(firstEditingPosition, visibleRange.end)\n    )\n  );\n}\n\nasync function refreshDiagnostics(\n  document: vscode.TextDocument,\n  diagnosticsCollection: vscode.DiagnosticCollection,\n  visibleRanges: vscode.Range[]\n): Promise<void> {\n  cancellationToken.cancel();\n  const lock = await mutex.acquire();\n  cancellationToken.reset();\n  cancellationToken.registerCallback(setStatusBarMessage);\n  try {\n    let foundDiagnostics = 0;\n    const relevantRange = getRelevantRange(document, visibleRanges);\n\n    if (!relevantRange) {\n      return;\n    }\n\n    const start = document.offsetAt(relevantRange.start);\n    const end = document.offsetAt(relevantRange.end);\n    const threshold =\n      getAssistantMode() === AssistantMode.Background\n        ? getBackgroundThreshold()\n        : PASTE_THRESHOLD;\n    const code = document.getText();\n    const apiKey = await getAPIKey();\n    if (cancellationToken.isCancelled()) {\n      return;\n    }\n    const assistantDiagnostics:\n      | AssistantDiagnostic[]\n      | undefined = await getAssistantDiagnostics(\n      code,\n      document.fileName,\n      { start, end },\n      threshold,\n      EDIT_DISTANCE,\n      apiKey,\n      cancellationToken\n    );\n    if (cancellationToken.isCancelled()) {\n      return;\n    }\n    const newDiagnostics: TabNineDiagnostic[] = [];\n    assistantDiagnostics?.forEach((assistantDiagnostic) => {\n      const choices = assistantDiagnostic.completionList.filter(\n        (completion) => completion.value !== assistantDiagnostic.reference\n      );\n      const choicesString = choices.map(\n        (completion) =>\n          `${completion.message} '${completion.value}'\\t${completion.score}%`\n      );\n      if (choices.length > 0) {\n        const prevReferencesLocationsInRange = assistantDiagnostic.references.filter(\n          (r) => r.start < assistantDiagnostic.range.start\n        );\n        const prevDiagnosticsForReferenceInRange = newDiagnostics.filter(\n          (diag) => prevReferencesLocationsInRange.includes(diag.assistantRange)\n        );\n\n        // If we are in paste mode and one of the previous reference was ok (no suggestions), don't suggest things on this reference.\n        if (\n          getAssistantMode() === AssistantMode.Background ||\n          prevReferencesLocationsInRange.length === 0 || // no references before this point\n          (prevReferencesLocationsInRange.length > 0 &&\n            prevDiagnosticsForReferenceInRange.length > 0)\n        ) {\n          // there are references before this point. and we have diagnostics for them\n          const vscodeRange = new vscode.Range(\n            document.positionAt(assistantDiagnostic.range.start),\n            document.positionAt(assistantDiagnostic.range.end)\n          );\n          const vscodeReferencesRange: vscode.Range[] = assistantDiagnostic.references.map(\n            (r) =>\n              new vscode.Range(\n                document.positionAt(r.start),\n                document.positionAt(r.end)\n              )\n          );\n          const diagnostic = new TabNineDiagnostic(\n            vscodeRange,\n            `${choicesString.join(\"\\n\")}`,\n            choices,\n            assistantDiagnostic.reference,\n            vscodeReferencesRange,\n            assistantDiagnostic.range,\n            assistantDiagnostic.responseId,\n            threshold,\n            vscode.DiagnosticSeverity.Information\n          );\n          diagnostic.code = TABNINE_DIAGNOSTIC_CODE;\n          newDiagnostics.push(diagnostic);\n          foundDiagnostics += 1;\n        }\n      }\n    });\n    if (newDiagnostics.length > 0) {\n      void setState({\n        ValidatorState: {\n          num_of_diagnostics: newDiagnostics.length,\n          num_of_locations: assistantDiagnostics?.length || 0,\n        },\n      });\n    }\n    if (\n      diagnosticsCollection.get(document.uri)?.length !== newDiagnostics.length\n    ) {\n      setDecorators(newDiagnostics);\n      diagnosticsCollection.set(document.uri, newDiagnostics);\n    }\n    const message = foundDiagnostics ? `${foundDiagnostics}` : \"\";\n    Logger.debug(message);\n    setStatusBarMessage(\"$(pass)\");\n  } catch (e: unknown) {\n    setStatusBarMessage();\n    Logger.error(`tabnine assistant: error: ${(e as Error).toString()}`);\n  } finally {\n    lock();\n  }\n}\nconst debouncedRefreshDiagnostics = debounce(refreshDiagnostics);\n\nfunction refreshDiagnosticsOrPrefetch(\n  document: vscode.TextDocument,\n  tabNineDiagnostics: vscode.DiagnosticCollection\n) {\n  if (getAssistantMode() === AssistantMode.Background) {\n    if (vscode.window.activeTextEditor) {\n      void refreshDiagnostics(\n        document,\n        tabNineDiagnostics,\n        vscode.window.activeTextEditor.visibleRanges\n      );\n    }\n  } else {\n    // prefetch diagnostics (getAssistantMode() == Mode.Paste)\n    void getCompilerDiagnostics(document.getText(), document.fileName);\n  }\n}\nlet currentRange: { range: vscode.Range; length: number } | null = null;\nlet inPaste = false;\n\nexport default async function registerAssistant(\n  context: vscode.ExtensionContext,\n  pasteDisposable: vscode.Disposable\n): Promise<void> {\n  const tabnineDiagnostics = vscode.languages.createDiagnosticCollection(\n    \"tabnine\"\n  );\n  context.subscriptions.push(tabnineDiagnostics);\n  const documentValidator = await getValidator();\n\n  initAssistantThreshold(context);\n\n  registerRefreshCommand(context, documentValidator, tabnineDiagnostics);\n\n  registerAssistantModeToggle(tabnineDiagnostics, documentValidator);\n\n  // handleActiveEditorChanged(context, documentValidator, tabnineDiagnostics);\n\n  handleVisibleRangeChange(context, documentValidator, tabnineDiagnostics);\n\n  pasteDisposable.dispose();\n  registerPasteCommand(context, documentValidator, tabnineDiagnostics);\n\n  // For AssistantMode.Paste\n  handlePasteChange(context, tabnineDiagnostics, documentValidator);\n\n  // For AssistantMode.Background\n  handleTextChange(context, tabnineDiagnostics, documentValidator);\n\n  void handleCodeAction(context);\n\n  // if (\n  //   getAssistantMode() === AssistantMode.Background &&\n  //   vscode.window.activeTextEditor &&\n  //   documentValidator.isValid(vscode.window.activeTextEditor.document)\n  // ) {\n  //   refreshDiagnosticsOrPrefetch(\n  //     vscode.window.activeTextEditor.document,\n  //     tabnineDiagnostics\n  //   );\n  // }\n}\n\nfunction registerRefreshCommand(\n  context: vscode.ExtensionContext,\n  documentValidator: DocumentValidator,\n  tabnineDiagnostics: vscode.DiagnosticCollection\n) {\n  context.subscriptions.push(\n    vscode.commands.registerCommand(ASSISTANT_IGNORE_REFRESH_COMMAND, () => {\n      const editor = vscode.window.activeTextEditor;\n      if (editor) {\n        const { document, visibleRanges } = editor;\n        if (documentValidator.isValid(document)) {\n          if (getAssistantMode() === AssistantMode.Paste) {\n            if (currentRange) {\n              void refreshDiagnostics(document, tabnineDiagnostics, [\n                currentRange?.range,\n              ]);\n            }\n          } else {\n            void refreshDiagnostics(\n              document,\n              tabnineDiagnostics,\n              visibleRanges\n            );\n          }\n        }\n      }\n    })\n  );\n}\n\nfunction registerAssistantModeToggle(\n  tabNineDiagnostics: vscode.DiagnosticCollection,\n  validator: DocumentValidator\n) {\n  vscode.commands.registerCommand(ASSISTANT_MODE_TOGGLE_COMMAND, () => {\n    cancellationToken.cancel();\n    if (vscode.window.activeTextEditor) {\n      tabNineDiagnostics.delete(vscode.window.activeTextEditor.document.uri);\n    }\n    setDecorators([]);\n    const newMode =\n      getAssistantMode() === AssistantMode.Background\n        ? AssistantMode.Paste\n        : AssistantMode.Background;\n    setAssistantMode(newMode);\n\n    if (getAssistantMode() === AssistantMode.Paste) {\n      void vscode.window.showInformationMessage(\"tabnine assistant paste mode\");\n      Logger.info(\"paste validation mode\");\n    } else {\n      void vscode.window.showInformationMessage(\n        \"tabnine assistant background mode\"\n      );\n      Logger.info(\"background validation mode\");\n    }\n\n    if (\n      vscode.window.activeTextEditor &&\n      validator.isValid(vscode.window.activeTextEditor.document)\n    ) {\n      refreshDiagnosticsOrPrefetch(\n        vscode.window.activeTextEditor.document,\n        tabNineDiagnostics\n      );\n    }\n  });\n}\n\n// function handleActiveEditorChanged(\n//   context: vscode.ExtensionContext,\n//   validator: DocumentValidator,\n//   tabNineDiagnostics: vscode.DiagnosticCollection\n// ) {\n//   context.subscriptions.push(\n//     vscode.window.onDidChangeActiveTextEditor((editor) => {\n//       if (editor && validator.isValid(editor.document)) {\n//         if (getAssistantMode() === AssistantMode.Background) {\n//           void refreshDiagnostics(\n//             editor.document,\n//             tabNineDiagnostics,\n//             editor.visibleRanges\n//           );\n//         } else {\n//           // prefetch diagnostics\n//           void getCompilerDiagnostics(\n//             editor.document.getText(),\n//             editor.document.fileName\n//           );\n//         }\n//       }\n//     })\n//   );\n// }\n\nfunction handleVisibleRangeChange(\n  context: vscode.ExtensionContext,\n  validator: DocumentValidator,\n  tabNineDiagnostics: vscode.DiagnosticCollection\n) {\n  context.subscriptions.push(\n    vscode.window.onDidChangeTextEditorVisibleRanges((event) => {\n      if (\n        getAssistantMode() === AssistantMode.Background &&\n        validator.isValid(event.textEditor.document)\n      ) {\n        debouncedRefreshDiagnostics(\n          event.textEditor.document,\n          tabNineDiagnostics,\n          event.textEditor.visibleRanges\n        );\n      }\n    })\n  );\n}\n\nfunction registerPasteCommand(\n  context: vscode.ExtensionContext,\n  validator: DocumentValidator,\n  tabNineDiagnostics: vscode.DiagnosticCollection\n) {\n  context.subscriptions.push(\n    vscode.commands.registerCommand(\n      PASTE_COMMAND,\n      async (textEditor: vscode.TextEditor) => {\n        inPaste = true;\n        const { start } = textEditor.selection;\n        await vscode.commands.executeCommand(\n          \"editor.action.clipboardPasteAction\"\n        );\n        const { end } = textEditor.selection;\n        if (vscode.window.activeTextEditor) {\n          const { document } = vscode.window.activeTextEditor;\n          const isValidExt = validator.isValid(document);\n          if (!isValidExt || getAssistantMode() === AssistantMode.Background) {\n            inPaste = false;\n            return;\n          }\n          currentRange = {\n            range: new vscode.Range(start, end),\n            length: document.offsetAt(end) - document.offsetAt(start),\n          };\n          inPaste = false;\n          tabNineDiagnostics.delete(document.uri);\n          setDecorators([]);\n          void refreshDiagnostics(document, tabNineDiagnostics, [\n            currentRange.range,\n          ]);\n        }\n      }\n    )\n  );\n}\n\nfunction handlePasteChange(\n  context: vscode.ExtensionContext,\n  assistantDiagnostics: vscode.DiagnosticCollection,\n  validator: DocumentValidator\n) {\n  context.subscriptions.push(\n    vscode.workspace.onDidChangeTextDocument((event) => {\n      if (\n        getAssistantMode() === AssistantMode.Paste &&\n        !inPaste &&\n        validator.isValid(event.document)\n      ) {\n        let firstPosition: vscode.Position | null = null;\n        let delta = 0;\n        event.contentChanges.forEach((cc) => {\n          if (firstPosition === null) {\n            firstPosition = cc.range.start;\n          } else if (cc.range.start.isBefore(firstPosition)) {\n            firstPosition = cc.range.start;\n          }\n          if (currentRange !== null) {\n            if (\n              cc.range.start.isAfterOrEqual(currentRange.range.start) &&\n              cc.range.end.isBefore(currentRange.range.end) &&\n              !(\n                cc.range.start.isEqual(currentRange.range.start) &&\n                cc.range.end.isEqual(currentRange.range.end)\n              )\n            ) {\n              delta += -cc.rangeLength + (cc.text.length || 0);\n            } else {\n              currentRange = null;\n            }\n          }\n        });\n        if (firstPosition !== null && currentRange !== null) {\n          const diagnostics = assistantDiagnostics\n            .get(event.document.uri)\n            ?.filter((d) =>\n              d.range.end.isBefore(firstPosition as vscode.Position)\n            );\n          assistantDiagnostics.set(event.document.uri, diagnostics);\n          setDecorators(diagnostics);\n          if (delta !== 0) {\n            const newLength = currentRange.length + delta;\n            const newEndPos = event.document.positionAt(\n              event.document.offsetAt(currentRange.range.start) + newLength\n            );\n            currentRange = {\n              range: new vscode.Range(currentRange.range.start, newEndPos),\n              length: newLength,\n            };\n          }\n          debouncedRefreshDiagnostics(event.document, assistantDiagnostics, [\n            currentRange.range,\n          ]);\n        } else {\n          assistantDiagnostics.delete(event.document.uri);\n          setDecorators([]);\n        }\n      }\n    })\n  );\n}\n\nfunction handleTextChange(\n  context: vscode.ExtensionContext,\n  assistantDiagnostics: vscode.DiagnosticCollection,\n  validator: DocumentValidator\n) {\n  context.subscriptions.push(\n    vscode.workspace.onDidChangeTextDocument((event) => {\n      if (\n        getAssistantMode() === AssistantMode.Background &&\n        validator.isValid(event.document) &&\n        event.contentChanges.length\n      ) {\n        const firstChangeStartPosition = event.contentChanges\n          .map((change) => change.range.start)\n          .reduce((first: vscode.Position | null, current) => {\n            if (first === null) {\n              return current;\n            }\n            if (current.isBefore(first)) {\n              return current;\n            }\n            return first;\n          }, null);\n\n        if (firstChangeStartPosition !== null) {\n          const diagnostics = assistantDiagnostics\n            .get(event.document.uri)\n            ?.filter((d) => d.range.end.isBefore(firstChangeStartPosition));\n          assistantDiagnostics.set(event.document.uri, diagnostics);\n          if (\n            assistantDiagnostics.get(event.document.uri)?.length !==\n            diagnostics?.length\n          ) {\n            setDecorators(diagnostics);\n          }\n          if (!changesTrackMap.has(event.document.uri)) {\n            changesTrackMap.set(event.document.uri, firstChangeStartPosition);\n          }\n        } else {\n          assistantDiagnostics.delete(event.document.uri);\n          setDecorators([]);\n        }\n        if (vscode.window.activeTextEditor) {\n          debouncedRefreshDiagnostics(\n            vscode.window.activeTextEditor.document,\n            assistantDiagnostics,\n            vscode.window.activeTextEditor.visibleRanges\n          );\n        }\n      }\n    })\n  );\n}\n\nasync function handleCodeAction(context: vscode.ExtensionContext) {\n  const validLanguages = await getValidLanguages();\n  context.subscriptions.push(\n    vscode.languages.registerCodeActionsProvider(\n      validLanguages,\n      new AssistantCodeActionProvider(),\n      {\n        providedCodeActionKinds:\n          AssistantCodeActionProvider.providedCodeActionKinds,\n      }\n    )\n  );\n}\n","import { Capability, isCapabilityEnabled } from \"../capabilities/capabilities\";\n\nconst MODE_A = \"A\";\nconst MODE_B = \"B\";\nexport default function getMode(): string {\n  if (isCapabilityEnabled(Capability.ASSISTANT_MODE_A_CAPABILITY_KEY)) {\n    return MODE_A;\n  }\n  if (isCapabilityEnabled(Capability.ASSISTANT_MODE_B_CAPABILITY_KEY)) {\n    return MODE_B;\n  }\n  return MODE_A; // default\n}\n","export const ASSISTANT_API_VERSION = \"1.0.0\";\nexport const TABNINE_DIAGNOSTIC_CODE = \"tabnine\";\nexport const ACTIVE_STATE_KEY = \"tabnine-assistant-active\";\nexport const ENABLED_KEY = \"tabnine-assistant:enabled\";\nexport const BACKGROUND_KEY = \"tabnine-assistant:background\";\nexport const CAPABILITY_KEY = \"tabnine-assistant:capability\";\nexport const THRESHOLD_STATE_KEY = \"tabnine-assistant-threshold\";\nexport const PASTE_THRESHOLD = \"Paste\";\nexport const EDIT_DISTANCE = 2;\nexport const ASSISTANT_SELECTION_COMMAND = \"tabnine-assistant-select\";\nexport const ASSISTANT_IGNORE_COMMAND = \"tabnine-assistant-ignore\";\nexport const ASSISTANT_IGNORE_REFRESH_COMMAND =\n  \"tabnine-assistant-ignore-refresh\";\nexport const ASSISTANT_MODE_TOGGLE_COMMAND = \"TabNine::assistantModeToggle\";\nexport const PASTE_COMMAND = \"TabNine::paste\";\nexport const ASSISTANT_CLEAR_CACHE_COMMAND = \"TabNine::assistantClearCache\";\nexport const ASSISTANT_SET_THRESHOLD_COMMAND = \"TabNine::assistantSetThreshold\";\nexport const ASSISTANT_TOGGLE_COMMAND = \"TabNine::assistantToggle\";\n","import * as vscode from \"vscode\";\nimport { getAssistantMode, AssistantMode } from \"./AssistantMode\";\nimport { StateType } from \"./utils\";\nimport setState from \"../binary/requests/setState\";\nimport { StatePayload } from \"../globals/consts\";\nimport {\n  ASSISTANT_IGNORE_REFRESH_COMMAND,\n  ASSISTANT_SET_THRESHOLD_COMMAND,\n  THRESHOLD_STATE_KEY,\n} from \"./globals\";\n\nlet backgroundThreshold = \"Medium\";\n\nexport function initAssistantThreshold(context: vscode.ExtensionContext): void {\n  backgroundThreshold =\n    context.workspaceState.get(THRESHOLD_STATE_KEY, backgroundThreshold) ||\n    backgroundThreshold;\n\n  registerSetThresholdCommand(context);\n}\n\nexport function getBackgroundThreshold(): string {\n  return backgroundThreshold;\n}\n\nfunction registerSetThresholdCommand(context: vscode.ExtensionContext) {\n  if (getAssistantMode() === AssistantMode.Background) {\n    context.subscriptions.push(\n      vscode.commands.registerCommand(\n        ASSISTANT_SET_THRESHOLD_COMMAND,\n        async () => {\n          const prevThreshold = backgroundThreshold;\n          const options: vscode.QuickPickOptions = {\n            canPickMany: false,\n            placeHolder: `Pick threshold (Currently: ${backgroundThreshold})`,\n          };\n          const items = [\"Low\", \"Medium\", \"High\"];\n          const value = await vscode.window.showQuickPick(items, options);\n          if (value && items.includes(value)) {\n            backgroundThreshold = value;\n            await context.workspaceState.update(\n              THRESHOLD_STATE_KEY,\n              backgroundThreshold\n            );\n            void setState({\n              [StatePayload.STATE]: {\n                state_type: StateType.threshold,\n                state: JSON.stringify({\n                  from: prevThreshold,\n                  to: backgroundThreshold,\n                }),\n              },\n            });\n            void vscode.commands.executeCommand(\n              ASSISTANT_IGNORE_REFRESH_COMMAND\n            );\n          }\n        }\n      )\n    );\n  }\n}\n","import { request } from \"./request\";\n\nexport default function clearCache(): Promise<string[]> {\n  const method = \"clear_cache\";\n  const body = {\n    method,\n    params: {},\n  };\n\n  return request(body) as Promise<string[]>;\n}\n","import { AssistantDiagnostic } from \"../AssistantDiagnostic\";\nimport CancellationToken from \"../CancellationToken\";\nimport getMode from \"../getMode\";\nimport { Range } from \"../Range\";\nimport { request } from \"./request\";\n\nexport default function getAssistantDiagnostics(\n  code: string,\n  fileName: string,\n  visibleRange: Range,\n  threshold: string,\n  editDistance: number,\n  apiKey: string,\n  cancellationToken: CancellationToken\n): Promise<AssistantDiagnostic[] | undefined> {\n  const body = {\n    method: \"get_assistant_diagnostics\",\n    params: {\n      code,\n      fileName,\n      visibleRange,\n      mode: getMode(),\n      threshold,\n      editDistance,\n      apiKey,\n    },\n  };\n  return request(body, cancellationToken);\n}\n","import { request } from \"./request\";\n\nexport default function getCompilerDiagnostics(\n  code: string,\n  fileName: string\n): Promise<string[]> {\n  const method = \"get_compiler_diagnostics\";\n  const body = {\n    method,\n    params: {\n      code,\n      fileName,\n    },\n  };\n  return request(body) as Promise<string[]>;\n}\n","import { request } from \"./request\";\n\nexport default function getValidExtensions(): Promise<string[]> {\n  const method = \"get_valid_extensions\";\n  const body = {\n    method,\n    params: {},\n  };\n  return request(body) as Promise<string[]>;\n}\n","import { request } from \"./request\";\n\nexport default function getValidLanguages(): Promise<string[]> {\n  const method = \"get_valid_languages\";\n  const body = {\n    method,\n    params: {},\n  };\n  return request(body) as Promise<string[]>;\n}\n","import { Logger } from \"../../utils/logger\";\nimport AssistantProcess from \"../AssistantProcess\";\nimport CancellationToken from \"../CancellationToken\";\nimport { ASSISTANT_API_VERSION } from \"../globals\";\nimport { getNanoSecTime } from \"../utils\";\n\nlet validationProcess: AssistantProcess | null = null;\nlet ASSISTANT_BINARY_VERSION: string | undefined;\n\nexport async function getAssistantVersion(): Promise<string> {\n  if (!ASSISTANT_BINARY_VERSION) {\n    ASSISTANT_BINARY_VERSION = await request({\n      method: \"get_version\",\n      params: {},\n    });\n  }\n  return ASSISTANT_BINARY_VERSION as string;\n}\n\nexport async function request<T, R>(\n  body: Record<string, T>,\n  cancellationToken?: CancellationToken\n): Promise<R | undefined> {\n  if (validationProcess === null) {\n    validationProcess = new AssistantProcess();\n  }\n\n  if (validationProcess.shutdowned) {\n    return undefined;\n  }\n\n  return new Promise((resolve, reject) => {\n    const id = getNanoSecTime();\n    cancellationToken?.registerCallback(resolve, undefined);\n\n    validationProcess\n      ?.post<{ id: number; version: string }, R>(\n        { ...body, id, version: ASSISTANT_API_VERSION },\n        id\n      )\n      .then(resolve, reject);\n  });\n}\n\nexport function closeAssistant(): Promise<unknown> {\n  Logger.warn(\"assistant is closing\");\n  if (validationProcess) {\n    const method = \"shutdown\";\n    const body = {\n      method,\n      params: {},\n    };\n    validationProcess.shutdowned = true;\n    return request(body);\n  }\n  return Promise.resolve();\n}\n","import { request } from \"./request\";\n\nexport default function setIgnore(responseId: string): Promise<string[]> {\n  const method = \"set_ignore\";\n  const body = {\n    method,\n    params: {\n      responseId,\n    },\n  };\n  return request(body) as Promise<string[]>;\n}\n","import * as child_process from \"child_process\";\nimport { getFullPathToAssistantBinary } from \"./utils\";\n\nexport default function run(\n  additionalArgs: string[] = [],\n  inheritStdio = false\n): child_process.ChildProcess {\n  const args = [...additionalArgs];\n  const command = getFullPathToAssistantBinary();\n  return child_process.spawn(command, args, {\n    stdio: inheritStdio ? \"inherit\" : \"pipe\",\n  });\n}\n","import * as fs from \"fs\";\nimport * as https from \"https\";\nimport * as vscode from \"vscode\";\nimport { getAssistantRootPath } from \"../binary/paths\";\nimport { getState } from \"../binary/requests/requests\";\nimport { State } from \"../binary/state\";\nimport { asyncExists } from \"../utils/file.utils\";\nimport sortBySemver from \"../utils/semver.utils\";\n\nconst fsp = fs.promises;\nconst assistantHost = \"update.tabnine.com\";\nconst assistantBinaryBaseName = \"tabnine-assistant\";\nconst statusBarItem = vscode.window.createStatusBarItem(\n  vscode.StatusBarAlignment.Right\n);\n\nexport const StateType = {\n  threshold: \"assistant-set-threshold-from-to\",\n  toggle: \"assistant-toggle\",\n  clearCache: \"validtor-clear-cache\",\n};\n\nlet state: State | null | undefined = null;\n\nexport async function getAPIKey(): Promise<string> {\n  if (state === null) {\n    state = await getState();\n  }\n\n  return state?.api_key || \"\";\n}\n\nexport async function downloadAssistantBinary(): Promise<boolean> {\n  if (state === null) {\n    state = await getState();\n  }\n  if (!state?.cloud_enabled) {\n    return false;\n  }\n\n  let tabNineVersionFromWeb: string;\n  try {\n    tabNineVersionFromWeb = await getTabNineAssistantVersionFromWeb();\n  } catch (e) {\n    // network problem, check if there is already some version on the machine\n    try {\n      getFullPathToAssistantBinary();\n      return true;\n    } catch (error) {\n      // binary doesn't exist\n      return false;\n    }\n  }\n\n  if (await asyncExists(getFullPathToAssistantBinary(tabNineVersionFromWeb))) {\n    return true;\n  }\n\n  return vscode.window.withProgress(\n    {\n      location: vscode.ProgressLocation.Notification,\n      cancellable: true,\n      title: `downloading tabnine assistant...`,\n    },\n    (progress, token) =>\n      new Promise((resolve, reject) => {\n        try {\n          const fullPath = getFullPathToAssistantBinary(tabNineVersionFromWeb);\n          const binaryDirPath = fullPath.slice(0, fullPath.lastIndexOf(\"/\"));\n          void fsp.mkdir(binaryDirPath, { recursive: true }).then(() => {\n            let totalBinaryLength: string | undefined;\n            const requestDownload = https.get(\n              {\n                timeout: 10_000,\n                hostname: assistantHost,\n                path: `/assistant/${fullPath.slice(\n                  fullPath.indexOf(tabNineVersionFromWeb)\n                )}`,\n              },\n              (res) => {\n                const binaryFile = fs.createWriteStream(fullPath, {\n                  mode: 0o755,\n                });\n                binaryFile.on(\"error\", (err) => reject(err));\n\n                let receivedBinaryLength = 0;\n                let binaryPercentage = 0;\n                res\n                  .on(\"data\", (chunk: { length: number }) => {\n                    if (!totalBinaryLength) {\n                      return;\n                    }\n\n                    receivedBinaryLength += chunk.length;\n                    const newBinaryPercentage = Number(\n                      (\n                        (receivedBinaryLength * 100) /\n                        Number.parseInt(totalBinaryLength, 10)\n                      ).toFixed()\n                    );\n\n                    if (binaryPercentage === 0) {\n                      progress.report({ increment: 0 });\n                    } else if (newBinaryPercentage > binaryPercentage) {\n                      progress.report({ increment: 1 });\n                    }\n\n                    binaryPercentage = newBinaryPercentage;\n                  })\n                  .on(\"error\", (err) => reject(err))\n                  .on(\"end\", () => {\n                    if (token.isCancellationRequested) {\n                      return;\n                    }\n\n                    progress.report({ increment: 100 });\n                    void vscode.window.showInformationMessage(\n                      `TabNine Assistant ${tabNineVersionFromWeb} binary is successfully downloaded`\n                    );\n                    resolve(true);\n                  })\n                  .pipe(binaryFile)\n                  .on(\"error\", (err) => reject(err));\n\n                token.onCancellationRequested(() => {\n                  res.destroy();\n                  binaryFile.destroy();\n                });\n              }\n            );\n\n            requestDownload.on(\n              \"response\",\n              (res: { headers: Record<string, string> }) => {\n                statusBarItem.text = \"tabnine assistant: $(sync~spin)\";\n                statusBarItem.tooltip = `downloading tabnine assistant ${tabNineVersionFromWeb} binary`;\n                totalBinaryLength = res.headers[\"content-length\"];\n              }\n            );\n            requestDownload.on(\"timeout\", () =>\n              reject(new Error(`Request to assistant timed out`))\n            );\n            requestDownload.on(\"error\", (err) => reject(err));\n\n            token.onCancellationRequested(() => {\n              fsp.unlink(fullPath).catch((err) => reject(err));\n              requestDownload.destroy(new Error(\"Canceled\"));\n              reject(\n                new Error(\n                  \"Download of tabnine assistant binary has been cancelled\"\n                )\n              );\n            });\n          });\n        } catch (err) {\n          reject(err);\n        }\n      })\n  );\n}\n\nasync function getTabNineAssistantVersionFromWeb(): Promise<string> {\n  return new Promise((resolve, reject) => {\n    const requestVersion = https.get(\n      { timeout: 10_000, hostname: assistantHost, path: `/assistant/version` },\n      (res) => {\n        let output = \"\";\n        res.on(\"data\", (chunk) => {\n          output += chunk;\n        });\n        res.on(\"end\", () => resolve(output.trim()));\n        res.on(\"error\", (err) => reject(err));\n      }\n    );\n    requestVersion.on(\"timeout\", () =>\n      reject(new Error(`Request to assistant version timed out`))\n    );\n    requestVersion.on(\"error\", (err) => reject(err));\n  });\n}\n\nexport function getFullPathToAssistantBinary(version?: string): string {\n  const architecture = getArchitecture();\n  const { target, filename } = getTargetAndFileNameByPlatform();\n  const assistantBinariesPath = getAssistantRootPath();\n\n  if (version === undefined) {\n    const versions = sortBySemver(fs.readdirSync(assistantBinariesPath));\n    const versionToRun = versions\n      .map(\n        (currentVersion) =>\n          `${assistantBinariesPath}/${currentVersion}/${architecture}-${target}/${filename}`\n      )\n      .find((fullPath) => fs.existsSync(fullPath));\n\n    if (!versionToRun) {\n      throw new Error(\n        `Couldn't find a TabNine Assistant binary (tried the following local versions: ${versions.join(\n          \", \"\n        )})`\n      );\n    }\n\n    return versionToRun;\n  }\n\n  return `${assistantBinariesPath}/${version}/${architecture}-${target}/${filename}`;\n}\n\nfunction getArchitecture(): string {\n  if (process.arch === \"x64\") {\n    return \"x86_64\";\n  }\n  if (process.arch === \"arm64\") {\n    return \"arm64\";\n  }\n  throw new Error(\n    `Architecture \"${process.arch}\" is not supported by tabnine assistant`\n  );\n}\n\nfunction getTargetAndFileNameByPlatform(): {\n  target: string;\n  filename: string;\n} {\n  if (process.platform === \"win32\") {\n    return {\n      target: \"pc-windows-msvc\",\n      filename: `${assistantBinaryBaseName}.exe`,\n    };\n  }\n  if (process.platform === \"darwin\") {\n    return { target: \"apple-darwin\", filename: assistantBinaryBaseName };\n  }\n  if (process.platform === \"linux\") {\n    return { target: \"unknown-linux-musl\", filename: assistantBinaryBaseName };\n  }\n  throw new Error(\n    `Platform \"${process.platform}\" is not supported by TabNine Assistant`\n  );\n}\n\nexport function getNanoSecTime(): number {\n  const [seconds, remainingNanoSecs] = process.hrtime();\n\n  return seconds * 1000000000 + remainingNanoSecs;\n}\n\nexport function debounce(\n  this: unknown,\n  // eslint-disable-next-line @typescript-eslint/no-explicit-any\n  func: (...args: any[]) => unknown,\n  timeout = 500\n): (...args: unknown[]) => unknown {\n  let timer: NodeJS.Timeout;\n  return (...args: unknown[]) => {\n    clearTimeout(timer);\n    timer = setTimeout(() => {\n      func.apply(this, args);\n    }, timeout);\n  };\n}\n","import {\n  authentication,\n  AuthenticationProvider,\n  AuthenticationProviderAuthenticationSessionsChangeEvent,\n  AuthenticationSession,\n  commands,\n  Disposable,\n  Event,\n  EventEmitter,\n} from \"vscode\";\nimport { once, EventEmitter as Emitter } from \"events\";\nimport { once as runOnce } from \"underscore\";\nimport { State } from \"../binary/state\";\nimport { BRAND_NAME } from \"../globals/consts\";\nimport { sleep } from \"../utils/utils\";\nimport { callForLogin, callForLogout } from \"./authentication.api\";\nimport TabnineSession from \"./TabnineSession\";\nimport BINARY_STATE from \"../binary/binaryStateSingleton\";\nimport { deriveNonNullState } from \"../state/deriveState\";\n\nconst LOGIN_HAPPENED_EVENT = \"loginHappened\";\n\ntype UserAuthData = {\n  username: string;\n  accessToken: string;\n};\n\ntype AuthStateData = {\n  current: UserAuthData | null;\n  last: UserAuthData | null;\n};\n\nconst AUTH_INITIAL_STATE = {\n  last: null,\n  current: null,\n};\n\nfunction toSession({ accessToken, username }: UserAuthData): TabnineSession {\n  return new TabnineSession(username, accessToken);\n}\n\nconst setAuthenticationReadyOnce = runOnce(setAuthenticationReady);\n\nexport default class TabnineAuthenticationProvider\n  implements AuthenticationProvider, Disposable {\n  public readonly id: string = BRAND_NAME;\n\n  public readonly label: string = BRAND_NAME;\n\n  private initializedDisposable: Disposable | undefined;\n\n  private onDidLogin = new Emitter();\n\n  private sessionsChangeEventEmitter = new EventEmitter<AuthenticationProviderAuthenticationSessionsChangeEvent>();\n\n  private authState = deriveNonNullState(\n    BINARY_STATE,\n    calculateAuthState,\n    AUTH_INITIAL_STATE\n  );\n\n  constructor() {\n    this.initializedDisposable = Disposable.from(\n      this.authState,\n      this.onDerivedAuthStateChanged(),\n      listenForSessionChangeFromVscode()\n    );\n  }\n\n  get onDidChangeSessions(): Event<AuthenticationProviderAuthenticationSessionsChangeEvent> {\n    return this.sessionsChangeEventEmitter.event;\n  }\n\n  async getSessions(): Promise<readonly AuthenticationSession[]> {\n    const userData = this.authState.get().current;\n\n    return Promise.resolve(userData ? [toSession(userData)] : []);\n  }\n\n  async createSession(): Promise<AuthenticationSession> {\n    await callForLogin();\n    const userAuth = await this.waitForLogin();\n\n    return toSession(userAuth);\n  }\n\n  private async waitForLogin(): Promise<UserAuthData> {\n    return ((await once(this.onDidLogin, LOGIN_HAPPENED_EVENT)) as [\n      UserAuthData\n    ])[0];\n  }\n\n  // eslint-disable-next-line class-methods-use-this\n  async removeSession(): Promise<void> {\n    await callForLogout();\n\n    await sleep(5000);\n  }\n\n  dispose(): void {\n    this.initializedDisposable?.dispose();\n  }\n\n  private onDerivedAuthStateChanged(): Disposable {\n    return this.authState.onChange(async ({ current, last }) => {\n      await setAuthenticationReadyOnce();\n\n      if (current && !last) {\n        this.onDidLogin.emit(LOGIN_HAPPENED_EVENT, current);\n      }\n\n      if (!current) {\n        await clearSessionPreference();\n      }\n\n      await setAuthenticationState(Boolean(current));\n      this.notifyVscodeOfAuthStateChanges(current, last);\n    });\n  }\n\n  private notifyVscodeOfAuthStateChanges(\n    current: UserAuthData | null,\n    last: UserAuthData | null\n  ) {\n    if (!last && current) {\n      this.sessionsChangeEventEmitter.fire({\n        added: [toSession(current)],\n      });\n    }\n\n    if (last && !current) {\n      this.sessionsChangeEventEmitter.fire({\n        removed: [toSession(last)],\n      });\n    }\n\n    if (last && current && last.accessToken !== current.accessToken) {\n      this.sessionsChangeEventEmitter.fire({\n        removed: [toSession(last)],\n        added: [toSession(current)],\n      });\n    }\n  }\n}\n\nasync function clearSessionPreference() {\n  await authentication.getSession(BRAND_NAME, [], {\n    clearSessionPreference: true,\n  });\n}\n\nfunction listenForSessionChangeFromVscode(): Disposable {\n  // This fires when the user initiates a \"silent\" auth flow via the Accounts menu.\n  return authentication.onDidChangeSessions((e) => {\n    if (e.provider.id === BRAND_NAME) {\n      void BINARY_STATE.checkForUpdates();\n    }\n  });\n}\n\nfunction calculateAuthState(binaryState: State, value: AuthStateData) {\n  const newValue: AuthStateData = {\n    last: value.current,\n    current: null,\n  };\n\n  if (binaryState.is_logged_in) {\n    newValue.current = {\n      accessToken: binaryState.access_token || \"\",\n      username: binaryState.user_name,\n    };\n  }\n\n  return newValue;\n}\n\nasync function setAuthenticationState(authenticated: boolean) {\n  return commands.executeCommand(\n    \"setContext\",\n    \"tabnine.authenticated\",\n    authenticated\n  );\n}\n\nasync function setAuthenticationReady() {\n  return commands.executeCommand(\n    \"setContext\",\n    \"tabnine.authentication.ready\",\n    true\n  );\n}\n","import { AuthenticationSession } from \"vscode\";\nimport { BRAND_NAME } from \"../globals/consts\";\n\nconst DEFAULT_USER_IDENTIFIER = \"Tabnine Authentication\";\n\nexport default class TabnineSession implements AuthenticationSession {\n  readonly id = BRAND_NAME;\n\n  readonly scopes = [];\n\n  readonly accessToken: string;\n\n  readonly account: { id: string; label: string };\n\n  constructor(userName: string = DEFAULT_USER_IDENTIFIER, accessToken = \"\") {\n    this.account = { id: userName, label: userName };\n    this.accessToken = accessToken;\n  }\n}\n","import { tabNineProcess } from \"../binary/requests/requests\";\nimport { openWebLogin } from \"../cloudEnvs/openLogin\";\nimport { notifyOnError } from \"../utils/notifyOnError\";\nimport { loginWithExternalProvider } from \"./loginWithExternalProvider\";\n\nexport async function callForLogin(): Promise<void> {\n  return callForLoginInternal();\n}\n\nexport async function callForLoginInternal(): Promise<void> {\n  return notifyOnError(openWebLogin, \"Failed to call for login\");\n}\n\nexport async function autoLoginExternal(): Promise<void> {\n  return notifyOnError(\n    loginWithExternalProvider,\n    \"Failed to call for login with external provider\"\n  );\n}\n\nexport async function callForLogout(): Promise<unknown> {\n  return notifyOnError(\n    () => tabNineProcess.request({ Logout: {} }),\n    \"Failed to call for logout\"\n  );\n}\n","import axios, { AxiosRequestConfig } from \"axios\";\nimport { notifyOnError } from \"../utils/notifyOnError\";\nimport { tabNineProcess } from \"../binary/requests/requests\";\nimport { getHttpAgent } from \"../utils/download.utils\";\nimport tabnineExtensionProperties from \"../globals/tabnineExtensionProperties\";\n\nexport interface AuthResponse {\n  authToken: string;\n}\n\nexport interface AuthRequest {\n  token: string;\n  provider: string;\n}\n\nexport async function getExternalProviderAuthUrl(): Promise<\n  string | null | undefined\n> {\n  return notifyOnError(\n    () =>\n      tabNineProcess.request(\n        {\n          ExternalProviderLoginUrl: {},\n        },\n        5000\n      ),\n    \"Failed to sign in using custom token url\"\n  );\n}\n\nexport async function externalAuth(\n  payload: AuthRequest\n): Promise<AuthResponse> {\n  const externalProviderAuthUrl = (await getExternalProviderAuthUrl()) as string;\n  if (!externalProviderAuthUrl) {\n    return Promise.reject(\n      new Error(\"External provider authentication URL not found\")\n    );\n  }\n\n  const config: AxiosRequestConfig = await axiosConfig(externalProviderAuthUrl);\n\n  const response = await axios.post<AuthResponse>(\n    externalProviderAuthUrl,\n    payload,\n    config\n  );\n\n  return response.data;\n}\nasync function axiosConfig(externalProviderAuthUrl: string) {\n  const parsedUrl = new URL(externalProviderAuthUrl);\n  const agent = await getHttpAgent(parsedUrl);\n\n  const config: AxiosRequestConfig = {\n    timeout: 10000,\n    headers: { \"User-Agent\": \"TabNine.tabnine-vscode\" },\n    httpsAgent: agent,\n    proxy: false,\n  };\n\n  if (tabnineExtensionProperties.ignoreCertificateErrors) {\n    config.httpsAgent = {\n      ...(config.httpsAgent as Record<string, unknown>),\n      rejectUnauthorized: false,\n    };\n  }\n  return config;\n}\n","export function isExternalIdentityDefined(): boolean {\n  return !!getExternalIdentityToken() && !!getExternalIdentityProvider();\n}\n\nexport function getExternalIdentityToken(): string | undefined {\n  return process.env.TABNINE_EXTERNAL_IDENTITY_TOKEN;\n}\n\nexport function getExternalIdentityProvider(): string | undefined {\n  return process.env.TABNINE_EXTERNAL_IDENTITY_PROVIDER;\n}\n","import { window, env, Uri } from \"vscode\";\nimport { notifyOnError } from \"../utils/notifyOnError\";\nimport { tabNineProcess } from \"../binary/requests/requests\";\n\nconst SIGN_IN = \"Sign in\";\nconst GET_AUTH_TOKEN = \"Get auth token\";\n\nexport async function signInUsingCustomToken(\n  customToke